  1	import * as React from 'react';
  2	import { useGetInternalClusterDetails } from '@odf/core/redux/utils';
  3	import { getResourceInNs as getCephClusterInNs } from '@odf/core/utils';
  4	import { resiliencyProgressQuery } from '@odf/ocs/queries';
  5	import {
  6	  getCephHealthChecks,
  7	  getCephHealthState,
  8	  getDataResiliencyState,
  9	} from '@odf/ocs/utils';
 10	import { odfDocBasePath } from '@odf/shared/constants/doc';
 11	import { healthStateMapping } from '@odf/shared/dashboards/status-card/states';
 12	import { DOC_VERSION as odfDocVersion } from '@odf/shared/hooks';
 13	import {
 14	  useCustomPrometheusPoll,
 15	  usePrometheusBasePath,
 16	} from '@odf/shared/hooks/custom-prometheus-poll';
 17	import { CephClusterModel } from '@odf/shared/models';
 18	import useAlerts from '@odf/shared/monitoring/useAlert';
 19	import { alertURL } from '@odf/shared/monitoring/utils';
 20	import { CephHealthCheckType, K8sResourceKind } from '@odf/shared/types';
 21	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 22	import { filterCephAlerts, referenceForModel } from '@odf/shared/utils';
 23	import {
 24	  Alert,
 25	  HealthState,
 26	  useK8sWatchResource,
 27	} from '@openshift-console/dynamic-plugin-sdk';
 28	import { SubsystemHealth } from '@openshift-console/dynamic-plugin-sdk/lib/extensions/dashboard-types';
 29	import {
 30	  AlertItem,
 31	  AlertsBody,
 32	  HealthItem,
 33	} from '@openshift-console/dynamic-plugin-sdk-internal';
 34	import * as _ from 'lodash-es';
 35	import {
 36	  Gallery,
 37	  GalleryItem,
 38	  Flex,
 39	  FlexItem,
 40	  Card,
 41	  CardHeader,
 42	  CardBody,
 43	  CardTitle,
 44	} from '@patternfly/react-core';
 45	import '../../../style.scss';
 46	import './healthchecks.scss';
 47	
 48	const generateDocumentationLink = (
 49	  alert: Alert,
 50	  docVersion: string
 51	): string => {
 52	  return `${odfDocBasePath(
 53	    docVersion
 54	  )}/troubleshooting_openshift_data_foundation/index#${_.toLower(
 55	    alert?.labels?.alertname
 56	  )}_rhodf`;
 57	};
 58	
 59	const isCephBasedAlert = (alert: Alert): boolean => {
 60	  return alert?.annotations?.storage_type === 'ceph';
 61	};
 62	
 63	const getDocumentationLink = (alert: Alert, docVersion: string): string => {
 64	  if (!!docVersion && isCephBasedAlert(alert)) {
 65	    return generateDocumentationLink(alert, docVersion);
 66	  }
 67	  return null;
 68	};
 69	
 70	const CephAlerts: React.FC<{ docVersion: string }> = ({ docVersion }) => {
 71	  const [alerts, loaded, error] = useAlerts();
 72	  // ToDo (epic 4422): Get StorageCluster name and namespace from the Alert object
 73	  // and filter Alerts based on that for a particular cluster.
 74	  const filteredAlerts =
 75	    loaded && !error && !_.isEmpty(alerts) ? filterCephAlerts(alerts) : [];
 76	
 77	  return (
 78	    <AlertsBody error={!_.isEmpty(error)}>
 79	      {loaded &&
 80	        filteredAlerts.length > 0 &&
 81	        filteredAlerts?.map((alert) => (
 82	          <AlertItem
 83	            key={alertURL(alert, alert?.rule?.id)}
 84	            alert={alert as any}
 85	            documentationLink={getDocumentationLink(alert, docVersion)}
 86	          />
 87	        ))}
 88	    </AlertsBody>
 89	  );
 90	};
 91	
 92	const CephHealthCheck: React.FC<CephHealthCheckProps> = ({
 93	  cephHealthState,
 94	  healthCheck,
 95	}) => {
 96	  const { t } = useCustomTranslation();
 97	  return (
 98	    <Flex flexWrap={{ default: 'nowrap' }} direction={{ default: 'row' }}>
 99	      <FlexItem>
100	        {
101	          (
102	            healthStateMapping[cephHealthState.state] ||
103	            healthStateMapping[HealthState.UNKNOWN]
104	          ).icon
105	        }
106	      </FlexItem>
107	      <FlexItem>
108	        <div data-test="healthcheck-message">{healthCheck?.details}</div>
109	      </FlexItem>
110	      <FlexItem>
111	        {!!healthCheck.troubleshootLink && (
112	          <a
113	            className="ceph-health-check-card__link"
114	            href={healthCheck.troubleshootLink}
115	          >
116	            {t('Troubleshoot')}
117	          </a>
118	        )}
119	      </FlexItem>
120	    </Flex>
121	  );
122	};
123	
124	const cephClusterResource = {
125	  kind: referenceForModel(CephClusterModel),
126	  isList: true,
127	};
128	
129	export const StatusCard: React.FC = () => {
130	  const { t } = useCustomTranslation();
131	  const [data, loaded, loadError] =
132	    useK8sWatchResource<K8sResourceKind[]>(cephClusterResource);
133	
134	  const { clusterNamespace: clusterNs, clusterName: managedByOCS } =
135	    useGetInternalClusterDetails();
136	
137	  const [resiliencyProgress, resiliencyProgressError] = useCustomPrometheusPoll(
138	    {
139	      query: resiliencyProgressQuery(managedByOCS),
140	      endpoint: 'api/v1/query' as any,
141	      basePath: usePrometheusBasePath(),
142	    }
143	  );
144	
145	  const cephCluster = getCephClusterInNs(data, clusterNs);
146	
147	  const cephHealthState = getCephHealthState(
148	    { ceph: { data: cephCluster, loaded, loadError } },
149	    t
150	  );
151	  const dataResiliencyState = getDataResiliencyState(
152	    [{ response: resiliencyProgress, error: resiliencyProgressError }],
153	    t
154	  );
155	
156	  const healthChecks = getCephHealthChecks(cephCluster);
157	
158	  return (
159	    <Card className="odf-overview-card--gradient">
160	      <CardHeader>
161	        <CardTitle>{t('Status')}</CardTitle>
162	      </CardHeader>
163	      <CardBody>
164	        <Gallery
165	          className="odf-overview-status__health pf-v6-u-mb-sm"
166	          hasGutter
167	        >
168	          <GalleryItem>
169	            <HealthItem
170	              title={t('Storage Cluster')}
171	              state={cephHealthState.state}
172	              details={cephHealthState.message}
173	              popupTitle={healthChecks ? t('Active health checks') : null}
174	            >
175	              {healthChecks?.map((healthCheck: CephHealthCheckType, i) => (
176	                <CephHealthCheck
177	                  key={`${i}`}
178	                  cephHealthState={cephHealthState}
179	                  healthCheck={healthCheck}
180	                />
181	              ))}
182	            </HealthItem>
183	          </GalleryItem>
184	          <GalleryItem>
185	            <HealthItem
186	              title={t('Data Resiliency')}
187	              state={dataResiliencyState.state}
188	              details={dataResiliencyState.message}
189	            />
190	          </GalleryItem>
191	        </Gallery>
192	        <CephAlerts docVersion={odfDocVersion} />
193	      </CardBody>
194	    </Card>
195	  );
196	};
197	
198	export default StatusCard;
199	
200	type CephHealthCheckProps = {
201	  cephHealthState: SubsystemHealth;
202	  healthCheck: CephHealthCheckType;
203	};

